/**
 * The Void — Dimensional Mastery Tests
 *
 * Verifies:
 * - Health scales with gnostic β₁ numbers (physics-native)
 * - Max HEX at Pleroma = 1220
 * - Stagnation grace = 42 at full mastery (the answer)
 * - Fast travel compression improves with mastery
 * - Modifiers stack correctly
 * - Optimism exhaust events format properly
 */

import { describe, it, expect } from 'vitest';
import {
  DIMENSIONAL_MASTERIES,
  calculateMasteryModifier,
  calculateEnergyCapacity,
  calculateStagnationGrace,
  calculateFastTravelCompression,
  formatExhaustForBridge,
  type OptimismExhaustEvent,
} from '../void-dimensional-mastery';

describe('void-dimensional-mastery', () => {
  // ── Health = Gnostic Number ─────────────────────────────────────

  describe('calculateEnergyCapacity', () => {
    it('fresh observer has 100 base energy', () => {
      expect(calculateEnergyCapacity(-1)).toBe(100); // No mastery
    });

    it('Bythos mastery adds nothing (β₁=0)', () => {
      expect(calculateEnergyCapacity(0)).toBe(100);
    });

    it('Proton mastery: 100 + (0+1+2+3)×10 = 160', () => {
      expect(calculateEnergyCapacity(3)).toBe(160);
    });

    it('Emanations mastery: 100 + (0+1+2+3+5+6)×10 = 270', () => {
      expect(calculateEnergyCapacity(5)).toBe(270);
    });

    it('Pleroma mastery: 100 + 112×10 = 1220', () => {
      // Sum of gnostic numbers: 0+1+2+3+5+6+9+10+21+55 = 112
      expect(calculateEnergyCapacity(9)).toBe(1220);
    });

    it('energy capacity scales purely with gnostic β₁ — no arbitrary numbers', () => {
      // Each step should add exactly β₁(d) × 10
      const beta1Values = [0, 1, 2, 3, 5, 6, 9, 10, 21, 55];
      let expectedEnergy = 100;
      for (let d = 0; d <= 9; d++) {
        expectedEnergy += beta1Values[d]! * 10;
        expect(calculateEnergyCapacity(d)).toBe(expectedEnergy);
      }
    });
  });

  // ── Stagnation Grace ────────────────────────────────────────────

  describe('calculateStagnationGrace', () => {
    it('base grace is 3 picolorenzos', () => {
      expect(calculateStagnationGrace(-1)).toBe(3);
    });

    it('full mastery grace = 42 (the answer to everything)', () => {
      // Base 3 + 0+1+1+2+2+3+4+5+8+13 = 3 + 39 = 42
      expect(calculateStagnationGrace(9)).toBe(42);
    });
  });

  // ── Fast Travel Compression ─────────────────────────────────────

  describe('calculateFastTravelCompression', () => {
    it('base compression = β₁_from / β₁_to', () => {
      // Dim 8→3 with no mastery: 21/3 = 7x
      const comp = calculateFastTravelCompression(8, 3, 0);
      expect(comp).toBeCloseTo(7, 0);
    });

    it('mastery increases compression', () => {
      const noMastery = calculateFastTravelCompression(8, 3, 0);
      const fullMastery = calculateFastTravelCompression(8, 3, 9);
      expect(fullMastery).toBeGreaterThan(noMastery);
    });

    it('teleport gets better with every dimension', () => {
      const compressions = [];
      for (let d = 0; d <= 9; d++) {
        compressions.push(calculateFastTravelCompression(8, 3, d));
      }
      // Each subsequent mastery should equal or increase compression
      for (let i = 1; i < compressions.length; i++) {
        expect(compressions[i]).toBeGreaterThanOrEqual(compressions[i - 1]!);
      }
    });
  });

  // ── Mastery Modifiers ───────────────────────────────────────────

  describe('calculateMasteryModifier', () => {
    it('no mastery = identity modifier', () => {
      const mod = calculateMasteryModifier(-1);
      expect(mod.rBonus).toBe(0);
      expect(mod.vMultiplier).toBe(1);
    });

    it('Pleroma mastery gives significant bonuses', () => {
      const mod = calculateMasteryModifier(9);
      expect(mod.rBonus).toBeGreaterThan(50);
      expect(mod.vMultiplier).toBeLessThan(0.5);
      expect(mod.wBonus).toBeGreaterThan(5);
      expect(mod.learningBonus).toBeGreaterThan(10);
    });

    it('v multiplier stacks multiplicatively (gets more powerful)', () => {
      const mod3 = calculateMasteryModifier(3);
      const mod9 = calculateMasteryModifier(9);
      expect(mod9.vMultiplier).toBeLessThan(mod3.vMultiplier);
    });

    it('caps moveCostReduction at 0.9', () => {
      const mod = calculateMasteryModifier(9);
      expect(mod.moveCostReduction).toBeLessThanOrEqual(0.9);
    });
  });

  // ── Mastery Table Integrity ─────────────────────────────────────

  describe('DIMENSIONAL_MASTERIES', () => {
    it('has exactly 10 entries (dims 0-9)', () => {
      expect(DIMENSIONAL_MASTERIES.size).toBe(10);
    });

    it('all entries have names and descriptions', () => {
      for (const [, m] of DIMENSIONAL_MASTERIES) {
        expect(m.name.length).toBeGreaterThan(0);
        expect(m.description.length).toBeGreaterThan(0);
      }
    });
  });

  // ── Optimism Exhaust ────────────────────────────────────────────

  describe('formatExhaustForBridge', () => {
    it('formats observer creation event', () => {
      const event: OptimismExhaustEvent = {
        type: 'observer_created',
        did: 'did:test:1',
        seed: 42,
        phyle: 'scientist',
        particleType: 'anyon',
      };
      const result = formatExhaustForBridge(event);
      expect(result.contractMethod).toBe('logGameExhaust');
      expect(result.args[0]).toBe('observer_created');
    });

    it('formats item drop event with improbability', () => {
      const event: OptimismExhaustEvent = {
        type: 'item_dropped',
        did: 'did:test:1',
        itemId: 'void-gap-walker-boots',
        rarity: 'mythic',
        improbability: 441,
        coordinateHash: 'abc123',
      };
      const result = formatExhaustForBridge(event);
      const parsed = JSON.parse(result.args[1] as string);
      expect(parsed.improbability).toBe(441);
    });
  });
});
